import sys
from typing import List

class Solution:
    def flipBits(self, nums: List[int]) -> int:
        result = 0
        for num in nums:
            flips = 0
            while num != 0:
                flips += num & 1
                num >>= 1
            result += flips
        return result

if __name__ == '__main__':
    s = Solution()
    nums = list(map(int, sys.stdin.readline().split()))
    print(s.flipBits(nums))

