#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
    int flipBits(vector<int>& nums){
        int result = 0;
        for (int i = 0; i < nums.size(); i++) {
            int num = nums[i];
            int flips = 0;
            while (num != 0) {
                flips += num & 1;
                num >>= 1;
            }
            result += flips;
        }
        return result;
    }
};

int main(){
    Solution s;
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++)
        cin >> nums[i];
    cout << s.flipBits(nums);
    return 0;
}
